86	export interface Damage {
87	  itemType: string;
88	  amount: number;
89	}
90	
91	export interface Incident {
92	  cause: string;
93	  damages: Damage[];
94	}
95	
96	export interface ClaimResult {
97	  payout: number;
98	  remainingCap: number;
99	}
100	
101	const insuranceValueByType: Record<string, number> = {
102	  sword: 1000,
103	  amulet: 600,
104	  staff: 800,
105	  potion: 400,
106	  rune: 250,
107	  moonstone: 250,
108	};
109	
110	const CAP_MULTIPLIER = 2;
111	const DEDUCTIBLE = 100;
112	const HALF_REIMBURSEMENT_ENCHANTMENT_THRESHOLD = 8;
113	const HALF_REIMBURSEMENT_RATE = 0.5;
114	
115	function totalInsuranceValue(policy: QuoteResult): number {
116	  return policy.items.reduce((sum, item) => sum + insuranceValueByType[item.type], 0);
117	}
118	
119	function remainingCapFor(policy: QuoteResult): number {
120	  return policy.remainingCap ?? CAP_MULTIPLIER * totalInsuranceValue(policy);
121	}
122	
123	function reimbursedAmount(damage: Damage, policy: QuoteResult): number {
124	  const damagedItem = policy.items.find((item) => item.type === damage.itemType);
125	  const halfReimbursementApplies =
126	    damagedItem !== undefined &&
127	    enchantmentLevel(damagedItem) >= HALF_REIMBURSEMENT_ENCHANTMENT_THRESHOLD;
128	  return halfReimbursementApplies
129	    ? damage.amount * HALF_REIMBURSEMENT_RATE
130	    : damage.amount;
131	}
132	
133	function payoutForDamage(damage: Damage, policy: QuoteResult): number {
134	  return reimbursedAmount(damage, policy) - DEDUCTIBLE;
135	}
136	
137	export function claim(policy: QuoteResult, incident: Incident): ClaimResult {
138	  const totalPayout = incident.damages.reduce(
139	    (total, damage) => total + payoutForDamage(damage, policy),
140	    0,
141	  );
142	  const desiredPayout = Math.floor(totalPayout);
143	  const remainingCapBefore = remainingCapFor(policy);
144	  const payout = Math.min(desiredPayout, remainingCapBefore);
145	  const remainingCap = remainingCapBefore - payout;
146	  policy.remainingCap = remainingCap;
147	  return { payout, remainingCap };
148	}
